effect.shader:
vec2 l2s( vec2 v ) {
    return (vec4(v,0.,1.)*acLayerToScreen).xy;
}

float gsmooth(float low, float high, float value) {
    float p = clamp((value-low)/(high-low),0.,1.);
    p -= 1.0;
    return pow(2.71828,-((p*p)/0.125));
}

void main() {
    vec2 st = acLayerNorm;
    vec2 center = centerPoint/1000. * vec2(1.,-1.);

    float insideLayer = step(0.0,acLayerNorm.x) * step(acLayerNorm.x,1.0) * step(0.0,acLayerNorm.y) * step(acLayerNorm.y,1.0);
    float damping = smoothstep(0.0,feather,acLayerNorm.x) * smoothstep(0.0,feather,acLayerNorm.y) * smoothstep(1.0,1.0-feather,acLayerNorm.x) * smoothstep(1.0,1.0-feather,acLayerNorm.y);

    st -= 0.5;
    st.x *= acLayerSize.x / acLayerSize.y;
    st -= center;
    float dist = length(st);
    vec2 prevSt = st;
    if ( dist < radius ) {
        float p = dist / radius;

        //p *= damping * insideLayer;

        if(strength > 0.) {
            if( gaussian ) {
                st *= mix(1.0, gsmooth(0.0, radius / dist, p), strength * 0.75);
            } else {
                st *= mix(1.0, smoothstep(0.0, radius / dist, p), strength * 0.75);
            }
        } else {
            st *= mix(1.0, pow(p, 1.0 + strength * 0.75) * radius / dist, 1.0 - p);
        }

        st = mix(prevSt,st,damping*insideLayer);
    }
    st += center;
    st.x /= acLayerSize.x / acLayerSize.y;
    st += 0.5;

    gl_FragColor = texture2DCv(inputImg.texture,l2s(st));

}
